using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class PatientService(IDbContextFactory<ApplicationDbContext> factory)
{
    // --- Owners ---

    public async Task<List<Owner>> GetOwnersAsync(string? search = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Owners.Include(o => o.Pets).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            var s = search.Trim().ToLower();
            q = q.Where(o => (o.FirstName + " " + o.LastName).ToLower().Contains(s)
                          || o.Phone.Contains(s));
        }
        return await q.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    public async Task<Owner?> GetOwnerAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);
    }

    public async Task SaveOwnerAsync(Owner owner)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (owner.Id == 0)
            db.Owners.Add(owner);
        else
            db.Owners.Update(owner);
        await db.SaveChangesAsync();
    }

    // --- Pets ---

    public async Task<List<Pet>> GetPetsAsync(string? search = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(search))
        {
            var s = search.Trim().ToLower();
            q = q.Where(p => p.Name.ToLower().Contains(s)
                          || (p.Owner.FirstName + " " + p.Owner.LastName).ToLower().Contains(s));
        }
        return await q.OrderBy(p => p.Name).ToListAsync();
    }

    public async Task<Pet?> GetPetAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes.OrderByDescending(t => t.Date))
            .FirstOrDefaultAsync(p => p.Id == id);
    }

    public async Task SavePetAsync(Pet pet)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (pet.Id == 0)
            db.Pets.Add(pet);
        else
            db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task DeletePetAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var pet = await db.Pets.FindAsync(id);
        if (pet is not null)
        {
            db.Pets.Remove(pet);
            await db.SaveChangesAsync();
        }
    }

    // --- Treatment Notes ---

    public async Task SaveTreatmentNoteAsync(TreatmentNote note)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (note.Id == 0)
            db.TreatmentNotes.Add(note);
        else
            db.TreatmentNotes.Update(note);
        await db.SaveChangesAsync();
    }

    public async Task DeleteTreatmentNoteAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var note = await db.TreatmentNotes.FindAsync(id);
        if (note is not null)
        {
            db.TreatmentNotes.Remove(note);
            await db.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(IDbContextFactory<ApplicationDbContext> factory)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue)
            q = q.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            q = q.Where(a => a.StartTime < to.Value);
        return await q.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (appointment.Id == 0)
            db.Appointments.Add(appointment);
        else
            db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var appt = await db.Appointments.FindAsync(id);
        if (appt is not null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<Appointment>> GetAvailableSlotsConflicts(DateTime start, int durationMinutes, int? excludeId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var end = start.AddMinutes(durationMinutes);
        return await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled
                     && (excludeId == null || a.Id != excludeId)
                     && a.StartTime < end
                     && EF.Functions.DateDiffMinute(a.StartTime, start) < a.DurationMinutes * -1 == false
                     && start < a.StartTime.AddMinutes(a.DurationMinutes)
                     )
            .ToListAsync();
    }

    public async Task<bool> HasConflict(DateTime start, int durationMinutes, int? excludeId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var end = start.AddMinutes(durationMinutes);
        return await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => excludeId == null || a.Id != excludeId)
            .AnyAsync(a => a.StartTime < end && start < a.StartTime.AddMinutes(a.DurationMinutes));
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(IDbContextFactory<ApplicationDbContext> factory)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .AsQueryable();
        if (status.HasValue)
            q = q.Where(i => i.Status == status.Value);
        return await q.OrderByDescending(i => i.Date).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (invoice.Id == 0)
        {
            db.Invoices.Add(invoice);
        }
        else
        {
            db.Invoices.Update(invoice);
        }
        await db.SaveChangesAsync();
    }

    public async Task AddLineItemAsync(InvoiceLineItem item)
    {
        await using var db = await factory.CreateDbContextAsync();
        db.InvoiceLineItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveLineItemAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var item = await db.InvoiceLineItems.FindAsync(id);
        if (item is not null)
