using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class AppointmentService(IDbContextFactory<ApplicationDbContext> factory)
{
    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (from.HasValue)
            q = q.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            q = q.Where(a => a.StartTime < to.Value);
        return await q.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task SaveAppointmentAsync(Appointment appointment)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (appointment.Id == 0)
            db.Appointments.Add(appointment);
        else
            db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var appt = await db.Appointments.FindAsync(id);
        if (appt is not null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<Appointment>> GetAvailableSlotsConflicts(DateTime start, int durationMinutes, int? excludeId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var end = start.AddMinutes(durationMinutes);
        return await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled
                     && (excludeId == null || a.Id != excludeId)
                     && a.StartTime < end
                     && EF.Functions.DateDiffMinute(a.StartTime, start) < a.DurationMinutes * -1 == false
                     && start < a.StartTime.AddMinutes(a.DurationMinutes)
                     )
            .ToListAsync();
    }

    public async Task<bool> HasConflict(DateTime start, int durationMinutes, int? excludeId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var end = start.AddMinutes(durationMinutes);
        return await db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => excludeId == null || a.Id != excludeId)
            .AnyAsync(a => a.StartTime < end && start < a.StartTime.AddMinutes(a.DurationMinutes));
    }
}

