using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(IDbContextFactory<ApplicationDbContext> factory)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .AsQueryable();
        if (status.HasValue)
            q = q.Where(i => i.Status == status.Value);
        return await q.OrderByDescending(i => i.Date).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .Include(i => i.Appointment)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task SaveInvoiceAsync(Invoice invoice)
    {
        await using var db = await factory.CreateDbContextAsync();
        if (invoice.Id == 0)
        {
            db.Invoices.Add(invoice);
        }
        else
        {
            db.Invoices.Update(invoice);
        }
        await db.SaveChangesAsync();
    }

    public async Task AddLineItemAsync(InvoiceLineItem item)
    {
        await using var db = await factory.CreateDbContextAsync();
        db.InvoiceLineItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task RemoveLineItemAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var item = await db.InvoiceLineItems.FindAsync(id);
        if (item is not null)
        {
            db.InvoiceLineItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task AddPaymentAsync(Payment payment)
    {
        await using var db = await factory.CreateDbContextAsync();
        db.Payments.Add(payment);

        // Auto-update invoice status if fully paid
        var invoice = await db.Invoices
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == payment.InvoiceId);
        if (invoice is not null)
        {
            var totalPaid = invoice.Payments.Sum(p => p.Amount) + payment.Amount;
            var totalDue = invoice.LineItems.Sum(li => li.Quantity * li.UnitPrice);
            if (totalPaid >= totalDue)
                invoice.Status = InvoiceStatus.Paid;
        }

        await db.SaveChangesAsync();
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        await using var db = await factory.CreateDbContextAsync();
        var q = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();
        if (invoiceId.HasValue)
            q = q.Where(p => p.InvoiceId == invoiceId.Value);
        return await q.OrderByDescending(p => p.Date).ToListAsync();
    }

    public async Task CancelInvoiceAsync(int id)
    {
        await using var db = await factory.CreateDbContextAsync();
        var invoice = await db.Invoices.FindAsync(id);
        if (invoice is not null)
        {
            invoice.Status = InvoiceStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }
}

