arguments.file_text:
@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc

<PageTitle>Patients</PageTitle>

<h1>🐕 Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input class="form-control" placeholder="Search pets or owners..." @bind="searchText" @bind:event="oninput" @bind:after="LoadDataAsync" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwnerAsync" FormName="ownerForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Address</label>
                    <InputText class="form-control" @bind-Value="editingOwner.Address" />
                </div>
                <button type="submit" class="btn btn-primary">Save Owner</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePetAsync" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.Species">
                            <option value="">Select...</option>
                            <option>Dog</option>
                            <option>Cat</option>
                            <option>Bird</option>
                            <option>Rabbit</option>
                            <option>Reptile</option>
                            <option>Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-8 mb-2">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingPet.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Save Pet</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPetForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (pets is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Pet Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Age</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pet in pets)
            {
                <tr>
                    <td>@pet.Name</td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.Owner.FullName</td>
                    <td>@(pet.DateOfBirth.HasValue ? $"{(DateTime.Today.DayNumber - pet.DateOfBirth.Value.DayNumber) / 365}y" : "—")</td>
                    <td>
                        <a href="patients/@pet.Id" class="btn btn-sm btn-outline-primary">View / History</a>
                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private List<Owner> owners = [];
    private string searchText = "";
    private bool showOwnerForm, showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    protected override async Task OnInitializedAsync() => await LoadDataAsync();

    private async Task LoadDataAsync()
    {
        pets = await PatientSvc.GetPetsAsync(searchText);
        owners = await PatientSvc.GetOwnersAsync();
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowAddPet()
    {
        editingPet = new Pet();
        showPetForm = true;
        showOwnerForm = false;
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, WeightKg = pet.WeightKg, Notes = pet.Notes, OwnerId = pet.OwnerId
        };
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwnerAsync()
    {
        await PatientSvc.SaveOwnerAsync(editingOwner);
        showOwnerForm = false;
        await LoadDataAsync();
    }

    private async Task SavePetAsync()
    {
        await PatientSvc.SavePetAsync(editingPet);
        showPetForm = false;
        await LoadDataAsync();
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc
@inject NavigationManager Nav
@using Microsoft.AspNetCore.Components.Authorization
@inject AuthenticationStateProvider AuthState

<PageTitle>Patient Details</PageTitle>

@if (pet is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>🐾 @pet.Name</h1>
    <p class="text-muted">
        @pet.Species @(string.IsNullOrEmpty(pet.Breed) ? "" : $"— {pet.Breed}") |
        Owner: <strong>@pet.Owner.FullName</strong> (@pet.Owner.Phone)
        @if (pet.DateOfBirth.HasValue) { <text>| DOB: @pet.DateOfBirth.Value.ToString("MMM d, yyyy")</text> }
        @if (pet.WeightKg.HasValue) { <text>| Weight: @pet.WeightKg.Value kg</text> }
    </p>
    @if (!string.IsNullOrEmpty(pet.Notes))
    {
        <div class="alert alert-info">@pet.Notes</div>
    }

    <hr />

    <h3>Medical History & Treatment Notes</h3>

    <button class="btn btn-primary mb-3" @onclick="ShowAddNote">+ Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-header">@(editingNote.Id == 0 ? "New Treatment Note" : "Edit Treatment Note")</div>
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="noteForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row">
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Summary</label>
                            <InputText class="form-control" @bind-Value="editingNote.Summary" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Medication</label>
                            <InputText class="form-control" @bind-Value="editingNote.Medication" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" rows="3" @bind-Value="editingNote.Description" />
                    </div>
                    <button type="submit" class="btn btn-primary">Save Note</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (pet.TreatmentNotes.Count == 0)
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5>@note.Summary</h5>
                        <small class="text-muted">@note.Date.ToString("MMM d, yyyy h:mm tt") — @note.StaffName</small>
                    </div>
                    @if (!string.IsNullOrEmpty(note.Diagnosis))
                    {
                        <p><strong>Diagnosis:</strong> @note.Diagnosis</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Medication))
                    {
                        <p><strong>Medication:</strong> @note.Medication</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Description))
                    {
                        <p>@note.Description</p>
                    }
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditNote(note)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeleteNoteAsync(note.Id)">Delete</button>
                </div>
            </div>
        }
    }

    <div class="mt-3">
        <a href="patients" class="btn btn-outline-secondary">← Back to Patients</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private TreatmentNote editingNote = new();
    private string currentUserName = "";

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthState.GetAuthenticationStateAsync();
        currentUserName = authState.User.Identity?.Name ?? "Staff";
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        pet = await PatientSvc.GetPetAsync(Id);
    }

    private void ShowAddNote()
    {
        editingNote = new TreatmentNote { PetId = Id, StaffName = currentUserName };
        showNoteForm = true;
    }

    private void EditNote(TreatmentNote note)
    {
        editingNote = new TreatmentNote
        {
            Id = note.Id, PetId = note.PetId, Summary = note.Summary,
            Description = note.Description, Diagnosis = note.Diagnosis,
            Medication = note.Medication, StaffName = note.StaffName, Date = note.Date
        };
        showNoteForm = true;
    }

    private async Task SaveNoteAsync()
    {
        await PatientSvc.SaveTreatmentNoteAsync(editingNote);
        showNoteForm = false;
        await LoadAsync();
    }

    private async Task DeleteNoteAsync(int noteId)
    {
        await PatientSvc.DeleteTreatmentNoteAsync(noteId);
        await LoadAsync();
    }
}

@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService ApptSvc
@inject PatientService PatientSvc
@inject AuthenticationStateProvider AuthState

<PageTitle>Appointments</PageTitle>

<h1>📅 Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Week of</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAsync" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-outline-secondary me-2" @onclick="PrevWeek">← Prev</button>
        <button class="btn btn-outline-secondary me-2" @onclick="() => { selectedDate = DateOnly.FromDateTime(DateTime.Today); _ = LoadAsync(); }">Today</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next →</button>
    </div>
    <div class="col-md-6 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="ShowAddForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppt.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppt" OnValidSubmit="SaveAsync" FormName="apptForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                @if (!string.IsNullOrEmpty(conflictMessage))
                {
                    <div class="alert alert-danger">@conflictMessage</div>
                }
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppt.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppt.StartTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="editingAppt.DurationMinutes" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppt.Reason" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Notes</label>
                    <InputText class="form-control" @bind-Value="editingAppt.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day == DateOnly.FromDateTime(DateTime.Today) ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@(new TimeOnly(hour, 0).ToString("h:mm tt"))</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotDate = weekStart.AddDays(d);
                        var slotStart = slotDate.ToDateTime(new TimeOnly(hour, 0));
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                        <td class="@(slotAppts.Count > 0 ? "" : "table-success")" style="font-size:0.8rem; cursor:pointer;"
                            @onclick="() => QuickAdd(slotStart)">
                            @foreach (var a in slotAppts)
                            {
                                <div class="@GetStatusBadgeClass(a.Status) mb-1 p-1 rounded">
                                    <strong>@a.StartTime.ToString("h:mm")</strong> @a.Pet.Name
                                    <br /><small>@a.Reason</small>
                                    @if (a.Status == AppointmentStatus.Scheduled)
                                    {
                                        <br />
                                        <button class="btn btn-outline-primary btn-sm py-0 mt-1" @onclick:stopPropagation @onclick="() => Reschedule(a)">Reschedule</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 mt-1" @onclick:stopPropagation @onclick="() => CancelAsync(a.Id)">Cancel</button>
                                    }
                                </div>
                            }
                            @if (slotAppts.Count == 0)
                            {
                                <small class="text-muted">Available</small>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    private DateOnly weekStart;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppt = new();
    private string? conflictMessage;
    private string currentUserName = "";

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthState.GetAuthenticationStateAsync();
        currentUserName = authState.User.Identity?.Name ?? "Staff";
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        int diff = (int)selectedDate.DayOfWeek;
        weekStart = selectedDate.AddDays(-diff);
        var from = weekStart.ToDateTime(TimeOnly.MinValue);
        var to = from.AddDays(7);
        appointments = await ApptSvc.GetAppointmentsAsync(from, to);
        pets = await PatientSvc.GetPetsAsync();
    }

    private void ShowAddForm()
    {
        editingAppt = new Appointment
        {
            StartTime = DateTime.Today.AddHours(9),
            DurationMinutes = 30,
            StaffName = currentUserName
        };
        conflictMessage = null;
        showForm = true;
    }

    private void QuickAdd(DateTime start)
    {
        editingAppt = new Appointment
        {
            StartTime = start,
            DurationMinutes = 30,
            StaffName = currentUserName
        };
        conflictMessage = null;
        showForm = true;
    }

    private void Reschedule(Appointment a)
    {
        editingAppt = new Appointment
        {
            Id = a.Id, PetId = a.PetId, StartTime = a.StartTime,
            DurationMinutes = a.DurationMinutes, Reason = a.Reason,
            Notes = a.Notes, StaffName = a.StaffName, Status = a.Status
        };
        conflictMessage = null;
        showForm = true;
    }

    private async Task SaveAsync()
    {
        bool conflict = await ApptSvc.HasConflict(editingAppt.StartTime, editingAppt.DurationMinutes, editingAppt.Id == 0 ? null : editingAppt.Id);
        if (conflict)
        {
            conflictMessage = "This time slot conflicts with an existing appointment. Please choose a different time.";
            return;
        }
        await ApptSvc.SaveAppointmentAsync(editingAppt);
        showForm = false;
        conflictMessage = null;
        await LoadAsync();
    }

    private async Task CancelAsync(int id)
    {
        await ApptSvc.CancelAppointmentAsync(id);
        await LoadAsync();
    }

    private void PrevWeek() { selectedDate = selectedDate.AddDays(-7); _ = LoadAsync(); }
    private void NextWeek() { selectedDate = selectedDate.AddDays(7); _ = LoadAsync(); }

    private static string GetStatusBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary bg-opacity-10",
        AppointmentStatus.Completed => "bg-secondary bg-opacity-10",
        AppointmentStatus.Cancelled => "bg-danger bg-opacity-10 text-decoration-line-through",
        _ => ""
    };
}

@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingSvc
@inject PatientService PatientSvc

<PageTitle>Billing</PageTitle>

<h1>💰 Billing & Invoices</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadAsync">
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="Paid">Paid</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
    <div class="col-md-8 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
        <a href="billing/payments" class="btn btn-outline-secondary ms-2">Payment History</a>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-header">New Invoice</div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoicePetId">
                        <option value="0">Select pet...</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                        }
                    </select>
                </div>
            </div>
            <h6>Line Items</h6>
            <table class="table table-sm">
                <thead>
                    <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr>
                </thead>
                <tbody>
                    @foreach (var item in newLineItems)
                    {
                        <tr>
                            <td><input class="form-control form-control-sm" @bind="item.Description" /></td>
                            <td style="width:80px"><input type="number" class="form-control form-control-sm" @bind="item.Quantity" min="1" /></td>
                            <td style="width:120px"><input type="number" class="form-control form-control-sm" @bind="item.UnitPrice" step="0.01" min="0" /></td>
                            <td>@((item.Quantity * item.UnitPrice).ToString("C"))</td>
                            <td><button class="btn btn-sm btn-outline-danger" @onclick="() => newLineItems.Remove(item)">×</button></td>
                        </tr>
                    }
                </tbody>
                <tfoot>
                    <tr>
                        <td colspan="3" class="text-end"><strong>Total:</strong></td>
                        <td><strong>@newLineItems.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</strong></td>
                        <td></td>
                    </tr>
