{"file_text": "@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc
@inject NavigationManager Nav
@using Microsoft.AspNetCore.Components.Authorization
@inject AuthenticationStateProvider AuthState

<PageTitle>Patient Details</PageTitle>

@if (pet is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>🐾 @pet.Name</h1>
    <p class="text-muted">
        @pet.Species @(string.IsNullOrEmpty(pet.Breed) ? "" : $"— {pet.Breed}") |
        Owner: <strong>@pet.Owner.FullName</strong> (@pet.Owner.Phone)
        @if (pet.DateOfBirth.HasValue) { <text>| DOB: @pet.DateOfBirth.Value.ToString("MMM d, yyyy")</text> }
        @if (pet.WeightKg.HasValue) { <text>| Weight: @pet.WeightKg.Value kg</text> }
    </p>
    @if (!string.IsNullOrEmpty(pet.Notes))
    {
        <div class="alert alert-info">@pet.Notes</div>
    }

    <hr />

    <h3>Medical History & Treatment Notes</h3>

    <button class="btn btn-primary mb-3" @onclick="ShowAddNote">+ Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-header">@(editingNote.Id == 0 ? "New Treatment Note" : "Edit Treatment Note")</div>
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="noteForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row">
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Summary</label>
                            <InputText class="form-control" @bind-Value="editingNote.Summary" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Medication</label>
                            <InputText class="form-control" @bind-Value="editingNote.Medication" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" rows="3" @bind-Value="editingNote.Description" />
                    </div>
                    <button type="submit" class="btn btn-primary">Save Note</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (pet.TreatmentNotes.Count == 0)
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5>@note.Summary</h5>
                        <small class="text-muted">@note.Date.ToString("MMM d, yyyy h:mm tt") — @note.StaffName</small>
                    </div>
                    @if (!string.IsNullOrEmpty(note.Diagnosis))
                    {
                        <p><strong>Diagnosis:</strong> @note.Diagnosis</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Medication))
                    {
                        <p><strong>Medication:</strong> @note.Medication</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Description))
                    {
                        <p>@note.Description</p>
                    }
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditNote(note)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeleteNoteAsync(note.Id)">Delete</button>
                </div>
            </div>
        }
    }

    <div class="mt-3">
        <a href="patients" class="btn btn-outline-secondary">← Back to Patients</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private TreatmentNote editingNote = new();
    private string currentUserName = "";

    protected override async Task OnInitializedAsync()
