        };
        showNoteForm = true;
    }

    private async Task SaveNoteAsync()
    {
        await PatientSvc.SaveTreatmentNoteAsync(editingNote);
        showNoteForm = false;
        await LoadAsync();
    }

    private async Task DeleteNoteAsync(int noteId)
    {
        await PatientSvc.DeleteTreatmentNoteAsync(noteId);
        await LoadAsync();
    }
}
