{"file_text": "@page "/billing/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingSvc

<PageTitle>Invoice Details</PageTitle>

@if (invoice is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Invoice INV-@invoice.Id.ToString("D4")</h1>
    <div class="row mb-3">
        <div class="col-md-6">
            <p><strong>Date:</strong> @invoice.Date.ToString("MMMM d, yyyy")</p>
            <p><strong>Pet:</strong> @invoice.Pet.Name (@invoice.Pet.Species)</p>
            <p><strong>Owner:</strong> @invoice.Pet.Owner.FullName — @invoice.Pet.Owner.Phone</p>
            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(invoice.Status)">@invoice.Status</span></p>
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table table-sm">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr></thead>
        <tbody>
            @foreach (var item in invoice.LineItems)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>@item.UnitPrice.ToString("C")</td>
                    <td>@item.LineTotal.ToString("C")</td>
                    <td>
                        @if (invoice.Status == InvoiceStatus.Pending)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItemAsync(item.Id)">Remove</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end"><strong>Total:</strong></td>
                <td><strong>@invoice.TotalAmount.ToString("C")</strong></td>
                <td></td>
            </tr>
        </tfoot>
    </table>

    @if (invoice.Status == InvoiceStatus.Pending)
    {
        <div class="card mb-3">
            <div class="card-header">Add Line Item</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-5">
                        <input class="form-control" placeholder="Description" @bind="newItem.Description" />
                    </div>
                    <div class="col-md-2">
                        <input type="number" class="form-control" placeholder="Qty" @bind="newItem.Quantity" min="1" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" class="form-control" placeholder="Unit Price" @bind="newItem.UnitPrice" step="0.01" min="0" />
                    </div>
                    <div class="col-md-2">
                        <button class="btn btn-success w-100" @onclick="AddItemAsync">Add</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <hr />

    <h4>Payments</h4>
    @if (invoice.Payments.Count == 0)
    {
        <p class="text-muted">No payments recorded yet.</p>
    }
    else
    {
        <table class="table table-sm">
            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Notes</th></tr></thead>
            <tbody>
                @foreach (var p in invoice.Payments)
                {
                    <tr>
                        <td>@p.Date.ToString("MMM d, yyyy h:mm tt")</td>
                        <td>@p.Amount.ToString("C")</td>
                        <td>@p.Method</td>
                        <td>@p.Notes</td>
                    </tr>
                }
            </tbody>
        </table>
    }

    <div class="row mb-2">
        <div class="col-md-6">
            <strong>Total Paid:</strong> @invoice.TotalPaid.ToString("C") |
            <strong class="@(invoice.BalanceDue > 0 ? "text-danger" : "text-success")">Balance Due: @invoice.BalanceDue.ToString("C")</strong>
        </div>
    </div>

    @if (invoice.Status == InvoiceStatus.Pending && invoice.BalanceDue > 0)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" @bind="newPayment.Amount" step="0.01" min="0.01" max="@((double)invoice.BalanceDue)" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            <option value="Cash">Cash</option>
                            <option value="Card">Card</option>
                            <option value="Check">Check</option>
                        </select>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Notes</label>
                        <input class="form-control" @bind="newPayment.Notes" />
                    </div>
                    <div class="col-md-2 d-flex align-items-end mb-2">
                        <button class="btn btn-success w-100" @onclick="ProcessPaymentAsync">Pay</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <a href="billing" class="btn btn-outline-secondary">← Back to Invoices</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private InvoiceLineItem newItem = new() { Quantity = 1 };
    private Payment newPayment = new();
    private string paymentMethod = "Cash";

    protected override async Task OnInitializedAsync() => await LoadAsync();

    private async Task LoadAsync()
    {
        invoice = await BillingSvc.GetInvoiceAsync(Id);
        newPayment = new Payment { InvoiceId = Id, Amount = invoice?.BalanceDue ?? 0 };
    }

    private async Task AddItemAsync()
    {
        if (string.IsNullOrWhiteSpace(newItem.Description)) return;
        newItem.InvoiceId = Id;
        await BillingSvc.AddLineItemAsync(newItem);
        newItem = new InvoiceLineItem { Quantity = 1 };
        await LoadAsync();
    }

    private async Task RemoveItemAsync(int itemId)
    {
        await BillingSvc.RemoveLineItemAsync(itemId);
        await LoadAsync();
    }

    private async Task ProcessPaymentAsync()
    {
        newPayment.Method = Enum.Parse<PaymentMethod>(paymentMethod);
        newPayment.InvoiceId = Id;
        await BillingSvc.AddPaymentAsync(newPayment);
        await LoadAsync();
    }

    private static string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
", "path": "/tmp/sv-4c1efaec61ad4092a05513afe03a16e7/VetClinic/Components/Pages/InvoiceDetail.razor"}

