@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc

<PageTitle>Patients</PageTitle>

<h1>🐕 Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input class="form-control" placeholder="Search pets or owners..." @bind="searchText" @bind:event="oninput" @bind:after="LoadDataAsync" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwnerAsync" FormName="ownerForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Address</label>
                    <InputText class="form-control" @bind-Value="editingOwner.Address" />
                </div>
                <button type="submit" class="btn btn-primary">Save Owner</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePetAsync" FormName="petForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.Species">
                            <option value="">Select...</option>
                            <option>Dog</option>
                            <option>Cat</option>
                            <option>Bird</option>
                            <option>Rabbit</option>
                            <option>Reptile</option>
                            <option>Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-8 mb-2">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingPet.Notes" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Save Pet</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPetForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (pets is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Pet Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Age</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pet in pets)
            {
                <tr>
                    <td>@pet.Name</td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.Owner.FullName</td>
                    <td>@(pet.DateOfBirth.HasValue ? $"{(DateTime.Today.DayNumber - pet.DateOfBirth.Value.DayNumber) / 365}y" : "—")</td>
                    <td>
                        <a href="patients/@pet.Id" class="btn btn-sm btn-outline-primary">View / History</a>
                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private List<Owner> owners = [];
    private string searchText = "";
    private bool showOwnerForm, showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    protected override async Task OnInitializedAsync() => await LoadDataAsync();

    private async Task LoadDataAsync()
    {
        pets = await PatientSvc.GetPetsAsync(searchText);
        owners = await PatientSvc.GetOwnersAsync();
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowAddPet()
    {
        editingPet = new Pet();
        showPetForm = true;
        showOwnerForm = false;
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, WeightKg = pet.WeightKg, Notes = pet.Notes, OwnerId = pet.OwnerId
        };
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwnerAsync()
    {
        await PatientSvc.SaveOwnerAsync(editingOwner);
        showOwnerForm = false;
        await LoadDataAsync();
    }

    private async Task SavePetAsync()
    {
        await PatientSvc.SavePetAsync(editingPet);
        showPetForm = false;
        await LoadDataAsync();
    }
}

@page "/patients/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientSvc
@inject NavigationManager Nav
@using Microsoft.AspNetCore.Components.Authorization
@inject AuthenticationStateProvider AuthState

<PageTitle>Patient Details</PageTitle>

@if (pet is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>🐾 @pet.Name</h1>
    <p class="text-muted">
        @pet.Species @(string.IsNullOrEmpty(pet.Breed) ? "" : $"— {pet.Breed}") |
        Owner: <strong>@pet.Owner.FullName</strong> (@pet.Owner.Phone)
        @if (pet.DateOfBirth.HasValue) { <text>| DOB: @pet.DateOfBirth.Value.ToString("MMM d, yyyy")</text> }
        @if (pet.WeightKg.HasValue) { <text>| Weight: @pet.WeightKg.Value kg</text> }
    </p>
    @if (!string.IsNullOrEmpty(pet.Notes))
    {
        <div class="alert alert-info">@pet.Notes</div>
    }

    <hr />

    <h3>Medical History & Treatment Notes</h3>

    <button class="btn btn-primary mb-3" @onclick="ShowAddNote">+ Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-header">@(editingNote.Id == 0 ? "New Treatment Note" : "Edit Treatment Note")</div>
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNoteAsync" FormName="noteForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary />
                    <div class="row">
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Summary</label>
                            <InputText class="form-control" @bind-Value="editingNote.Summary" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Diagnosis</label>
                            <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Medication</label>
                            <InputText class="form-control" @bind-Value="editingNote.Medication" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Description</label>
                        <InputTextArea class="form-control" rows="3" @bind-Value="editingNote.Description" />
                    </div>
                    <button type="submit" class="btn btn-primary">Save Note</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (pet.TreatmentNotes.Count == 0)
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
    else
    {
        @foreach (var note in pet.TreatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <div class="d-flex justify-content-between">
                        <h5>@note.Summary</h5>
                        <small class="text-muted">@note.Date.ToString("MMM d, yyyy h:mm tt") — @note.StaffName</small>
                    </div>
                    @if (!string.IsNullOrEmpty(note.Diagnosis))
                    {
                        <p><strong>Diagnosis:</strong> @note.Diagnosis</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Medication))
                    {
                        <p><strong>Medication:</strong> @note.Medication</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Description))
                    {
                        <p>@note.Description</p>
                    }
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditNote(note)">Edit</button>
                    <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeleteNoteAsync(note.Id)">Delete</button>
                </div>
            </div>
        }
    }

    <div class="mt-3">
        <a href="patients" class="btn btn-outline-secondary">← Back to Patients</a>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private TreatmentNote editingNote = new();
    private string currentUserName = "";

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthState.GetAuthenticationStateAsync();
        currentUserName = authState.User.Identity?.Name ?? "Staff";
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        pet = await PatientSvc.GetPetAsync(Id);
    }

    private void ShowAddNote()
    {
        editingNote = new TreatmentNote { PetId = Id, StaffName = currentUserName };
        showNoteForm = true;
    }

    private void EditNote(TreatmentNote note)
    {
        editingNote = new TreatmentNote
        {
            Id = note.Id, PetId = note.PetId, Summary = note.Summary,
            Description = note.Description, Diagnosis = note.Diagnosis,
            Medication = note.Medication, StaffName = note.StaffName, Date = note.Date
        };
        showNoteForm = true;
    }

    private async Task SaveNoteAsync()
    {
        await PatientSvc.SaveTreatmentNoteAsync(editingNote);
        showNoteForm = false;
        await LoadAsync();
    }

    private async Task DeleteNoteAsync(int noteId)
    {
        await PatientSvc.DeleteTreatmentNoteAsync(noteId);
        await LoadAsync();
    }
}

