@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService ApptSvc
@inject PatientService PatientSvc
@inject AuthenticationStateProvider AuthState

<PageTitle>Appointments</PageTitle>

<h1>📅 Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Week of</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAsync" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-outline-secondary me-2" @onclick="PrevWeek">← Prev</button>
        <button class="btn btn-outline-secondary me-2" @onclick="() => { selectedDate = DateOnly.FromDateTime(DateTime.Today); _ = LoadAsync(); }">Today</button>
        <button class="btn btn-outline-secondary" @onclick="NextWeek">Next →</button>
    </div>
    <div class="col-md-6 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="ShowAddForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppt.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppt" OnValidSubmit="SaveAsync" FormName="apptForm">
                <DataAnnotationsValidator />
                <ValidationSummary />
                @if (!string.IsNullOrEmpty(conflictMessage))
                {
                    <div class="alert alert-danger">@conflictMessage</div>
                }
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppt.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Date & Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppt.StartTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label class="form-label">Duration (min)</label>
                        <InputNumber class="form-control" @bind-Value="editingAppt.DurationMinutes" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppt.Reason" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Notes</label>
                    <InputText class="form-control" @bind-Value="editingAppt.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<div class="table-responsive">
    <table class="table table-bordered">
        <thead class="table-light">
            <tr>
                <th style="width:80px">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="@(day == DateOnly.FromDateTime(DateTime.Today) ? "table-active" : "")">
                        @day.ToString("ddd M/d")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour < 18; hour++)
            {
                <tr>
                    <td class="text-muted small">@(new TimeOnly(hour, 0).ToString("h:mm tt"))</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotDate = weekStart.AddDays(d);
                        var slotStart = slotDate.ToDateTime(new TimeOnly(hour, 0));
                        var slotEnd = slotStart.AddHours(1);
                        var slotAppts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                        <td class="@(slotAppts.Count > 0 ? "" : "table-success")" style="font-size:0.8rem; cursor:pointer;"
                            @onclick="() => QuickAdd(slotStart)">
                            @foreach (var a in slotAppts)
                            {
                                <div class="@GetStatusBadgeClass(a.Status) mb-1 p-1 rounded">
                                    <strong>@a.StartTime.ToString("h:mm")</strong> @a.Pet.Name
                                    <br /><small>@a.Reason</small>
                                    @if (a.Status == AppointmentStatus.Scheduled)
                                    {
                                        <br />
                                        <button class="btn btn-outline-primary btn-sm py-0 mt-1" @onclick:stopPropagation @onclick="() => Reschedule(a)">Reschedule</button>
                                        <button class="btn btn-outline-danger btn-sm py-0 mt-1" @onclick:stopPropagation @onclick="() => CancelAsync(a.Id)">Cancel</button>
                                    }
                                </div>
                            }
                            @if (slotAppts.Count == 0)
                            {
                                <small class="text-muted">Available</small>
                            }
                        </td>
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateOnly selectedDate = DateOnly.FromDateTime(DateTime.Today);
    private DateOnly weekStart;
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private bool showForm;
    private Appointment editingAppt = new();
    private string? conflictMessage;
    private string currentUserName = "";

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthState.GetAuthenticationStateAsync();
        currentUserName = authState.User.Identity?.Name ?? "Staff";
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        int diff = (int)selectedDate.DayOfWeek;
        weekStart = selectedDate.AddDays(-diff);
        var from = weekStart.ToDateTime(TimeOnly.MinValue);
        var to = from.AddDays(7);
        appointments = await ApptSvc.GetAppointmentsAsync(from, to);
        pets = await PatientSvc.GetPetsAsync();
    }

    private void ShowAddForm()
    {
        editingAppt = new Appointment
        {
            StartTime = DateTime.Today.AddHours(9),
            DurationMinutes = 30,
            StaffName = currentUserName
        };
        conflictMessage = null;
        showForm = true;
    }

    private void QuickAdd(DateTime start)
    {
        editingAppt = new Appointment
        {
            StartTime = start,
            DurationMinutes = 30,
            StaffName = currentUserName
        };
        conflictMessage = null;
        showForm = true;
    }

    private void Reschedule(Appointment a)
    {
        editingAppt = new Appointment
        {
            Id = a.Id, PetId = a.PetId, StartTime = a.StartTime,
            DurationMinutes = a.DurationMinutes, Reason = a.Reason,
            Notes = a.Notes, StaffName = a.StaffName, Status = a.Status
        };
        conflictMessage = null;
        showForm = true;
    }

    private async Task SaveAsync()
    {
        bool conflict = await ApptSvc.HasConflict(editingAppt.StartTime, editingAppt.DurationMinutes, editingAppt.Id == 0 ? null : editingAppt.Id);
        if (conflict)
        {
            conflictMessage = "This time slot conflicts with an existing appointment. Please choose a different time.";
            return;
        }
        await ApptSvc.SaveAppointmentAsync(editingAppt);
        showForm = false;
        conflictMessage = null;
        await LoadAsync();
    }

    private async Task CancelAsync(int id)
    {
        await ApptSvc.CancelAppointmentAsync(id);
        await LoadAsync();
    }

    private void PrevWeek() { selectedDate = selectedDate.AddDays(-7); _ = LoadAsync(); }
    private void NextWeek() { selectedDate = selectedDate.AddDays(7); _ = LoadAsync(); }

    private static string GetStatusBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary bg-opacity-10",
        AppointmentStatus.Completed => "bg-secondary bg-opacity-10",
        AppointmentStatus.Cancelled => "bg-danger bg-opacity-10 text-decoration-line-through",
        _ => ""
    };
}

