@page "/billing"
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingSvc
@inject PatientService PatientSvc

<PageTitle>Billing</PageTitle>

<h1>💰 Billing & Invoices</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Filter by Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadAsync">
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="Paid">Paid</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
    <div class="col-md-8 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
        <a href="billing/payments" class="btn btn-outline-secondary ms-2">Payment History</a>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-header">New Invoice</div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoicePetId">
                        <option value="0">Select pet...</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                        }
                    </select>
                </div>
            </div>
            <h6>Line Items</h6>
            <table class="table table-sm">
                <thead>
                    <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr>
                </thead>
                <tbody>
                    @foreach (var item in newLineItems)
                    {
                        <tr>
                            <td><input class="form-control form-control-sm" @bind="item.Description" /></td>
                            <td style="width:80px"><input type="number" class="form-control form-control-sm" @bind="item.Quantity" min="1" /></td>
                            <td style="width:120px"><input type="number" class="form-control form-control-sm" @bind="item.UnitPrice" step="0.01" min="0" /></td>
                            <td>@((item.Quantity * item.UnitPrice).ToString("C"))</td>
                            <td><button class="btn btn-sm btn-outline-danger" @onclick="() => newLineItems.Remove(item)">×</button></td>
                        </tr>
                    }
                </tbody>
                <tfoot>
                    <tr>
                        <td colspan="3" class="text-end"><strong>Total:</strong></td>
                        <td><strong>@newLineItems.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</strong></td>
                        <td></td>
                    </tr>
                </tfoot>
            </table>
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="() => newLineItems.Add(new InvoiceLineItem())">+ Add Item</button>
            <div>
                <button class="btn btn-primary" @onclick="CreateInvoiceAsync" disabled="@(newInvoicePetId == 0 || newLineItems.Count == 0)">Create Invoice</button>
                <button class="btn btn-secondary ms-2" @onclick="() => showInvoiceForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (invoices is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Invoice #</th>
                <th>Date</th>
                <th>Pet</th>
                <th>Owner</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Balance</th>
                <th>Status</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>INV-@inv.Id.ToString("D4")</td>
                    <td>@inv.Date.ToString("MMM d, yyyy")</td>
                    <td>@inv.Pet.Name</td>
                    <td>@inv.Pet.Owner.FullName</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.TotalPaid.ToString("C")</td>
                    <td class="@(inv.BalanceDue > 0 ? "text-danger fw-bold" : "text-success")">@inv.BalanceDue.ToString("C")</td>
                    <td>
                        <span class="badge @GetStatusBadge(inv.Status)">@inv.Status</span>
                    </td>
                    <td>
                        <a href="billing/@inv.Id" class="btn btn-sm btn-outline-primary">Details</a>
                        @if (inv.Status == InvoiceStatus.Pending)
                        {
                            <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => CancelInvoiceAsync(inv.Id)">Cancel</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Invoice>? invoices;
    private List<Pet> pets = [];
    private string statusFilter = "";
    private bool showInvoiceForm;
    private int newInvoicePetId;
    private List<InvoiceLineItem> newLineItems = [];

    protected override async Task OnInitializedAsync() => await LoadAsync();

    private async Task LoadAsync()
    {
        InvoiceStatus? status = Enum.TryParse<InvoiceStatus>(statusFilter, out var s) ? s : null;
        invoices = await BillingSvc.GetInvoicesAsync(status);
        pets = await PatientSvc.GetPetsAsync();
    }

    private void ShowNewInvoice()
    {
        newInvoicePetId = 0;
        newLineItems = [new InvoiceLineItem()];
        showInvoiceForm = true;
    }

    private async Task CreateInvoiceAsync()
    {
        var invoice = new Invoice
        {
            PetId = newInvoicePetId,
            LineItems = newLineItems.Where(i => !string.IsNullOrWhiteSpace(i.Description)).ToList()
        };
        await BillingSvc.SaveInvoiceAsync(invoice);
        showInvoiceForm = false;
        await LoadAsync();
    }

    private async Task CancelInvoiceAsync(int id)
    {
        await BillingSvc.CancelInvoiceAsync(id);
        await LoadAsync();
    }

    private static string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/billing/{Id:int}"
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingSvc

<PageTitle>Invoice Details</PageTitle>

@if (invoice is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Invoice INV-@invoice.Id.ToString("D4")</h1>
    <div class="row mb-3">
        <div class="col-md-6">
            <p><strong>Date:</strong> @invoice.Date.ToString("MMMM d, yyyy")</p>
            <p><strong>Pet:</strong> @invoice.Pet.Name (@invoice.Pet.Species)</p>
            <p><strong>Owner:</strong> @invoice.Pet.Owner.FullName — @invoice.Pet.Owner.Phone</p>
            <p><strong>Status:</strong> <span class="badge @GetStatusBadge(invoice.Status)">@invoice.Status</span></p>
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table table-sm">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr></thead>
        <tbody>
            @foreach (var item in invoice.LineItems)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>@item.UnitPrice.ToString("C")</td>
                    <td>@item.LineTotal.ToString("C")</td>
                    <td>
                        @if (invoice.Status == InvoiceStatus.Pending)
                        {
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveItemAsync(item.Id)">Remove</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end"><strong>Total:</strong></td>
                <td><strong>@invoice.TotalAmount.ToString("C")</strong></td>
                <td></td>
            </tr>
        </tfoot>
    </table>

    @if (invoice.Status == InvoiceStatus.Pending)
    {
        <div class="card mb-3">
            <div class="card-header">Add Line Item</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-5">
                        <input class="form-control" placeholder="Description" @bind="newItem.Description" />
                    </div>
                    <div class="col-md-2">
                        <input type="number" class="form-control" placeholder="Qty" @bind="newItem.Quantity" min="1" />
                    </div>
                    <div class="col-md-3">
                        <input type="number" class="form-control" placeholder="Unit Price" @bind="newItem.UnitPrice" step="0.01" min="0" />
                    </div>
                    <div class="col-md-2">
                        <button class="btn btn-success w-100" @onclick="AddItemAsync">Add</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <hr />

    <h4>Payments</h4>
    @if (invoice.Payments.Count == 0)
    {
        <p class="text-muted">No payments recorded yet.</p>
    }
    else
    {
        <table class="table table-sm">
            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Notes</th></tr></thead>
            <tbody>
                @foreach (var p in invoice.Payments)
                {
                    <tr>
                        <td>@p.Date.ToString("MMM d, yyyy h:mm tt")</td>
                        <td>@p.Amount.ToString("C")</td>
                        <td>@p.Method</td>
                        <td>@p.Notes</td>
                    </tr>
                }
            </tbody>
        </table>
    }

    <div class="row mb-2">
        <div class="col-md-6">
            <strong>Total Paid:</strong> @invoice.TotalPaid.ToString("C") |
            <strong class="@(invoice.BalanceDue > 0 ? "text-danger" : "text-success")">Balance Due: @invoice.BalanceDue.ToString("C")</strong>
        </div>
    </div>

    @if (invoice.Status == InvoiceStatus.Pending && invoice.BalanceDue > 0)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment</div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" @bind="newPayment.Amount" step="0.01" min="0.01" max="@((double)invoice.BalanceDue)" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            <option value="Cash">Cash</option>
                            <option value="Card">Card</option>
                            <option value="Check">Check</option>
                        </select>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Notes</label>
                        <input class="form-control" @bind="newPayment.Notes" />
                    </div>
                    <div class="col-md-2 d-flex align-items-end mb-2">
                        <button class="btn btn-success w-100" @onclick="ProcessPaymentAsync">Pay</button>
                    </div>
                </div>
            </div>
        </div>
    }

    <a href="billing" class="btn btn-outline-secondary">← Back to Invoices</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private InvoiceLineItem newItem = new() { Quantity = 1 };
    private Payment newPayment = new();
    private string paymentMethod = "Cash";

    protected override async Task OnInitializedAsync() => await LoadAsync();

    private async Task LoadAsync()
    {
        invoice = await BillingSvc.GetInvoiceAsync(Id);
        newPayment = new Payment { InvoiceId = Id, Amount = invoice?.BalanceDue ?? 0 };
    }

    private async Task AddItemAsync()
    {
        if (string.IsNullOrWhiteSpace(newItem.Description)) return;
        newItem.InvoiceId = Id;
        await BillingSvc.AddLineItemAsync(newItem);
        newItem = new InvoiceLineItem { Quantity = 1 };
        await LoadAsync();
    }

    private async Task RemoveItemAsync(int itemId)
    {
        await BillingSvc.RemoveLineItemAsync(itemId);
        await LoadAsync();
    }

    private async Task ProcessPaymentAsync()
    {
        newPayment.Method = Enum.Parse<PaymentMethod>(paymentMethod);
        newPayment.InvoiceId = Id;
        await BillingSvc.AddPaymentAsync(newPayment);
        await LoadAsync();
    }

    private static string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

