        <tbody>
            @foreach (var p in payments)
            {
                <tr>
                    <td>@p.Date.ToString("MMM d, yyyy h:mm tt")</td>
                    <td><a href="billing/@p.InvoiceId">INV-@p.InvoiceId.ToString("D4")</a></td>
                    <td>@p.Invoice.Pet.Name</td>
                    <td>@p.Invoice.Pet.Owner.FullName</td>
                    <td>@p.Amount.ToString("C")</td>
                    <td>@p.Method</td>
                    <td>@p.Notes</td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="4" class="text-end"><strong>Total Received:</strong></td>
                <td><strong>@payments.Sum(p => p.Amount).ToString("C")</strong></td>
                <td colspan="2"></td>
            </tr>
        </tfoot>
    </table>
}

