public async Task<List<Appointment>> GetAvailableSlotsConflicts(DateTime start, int durationMinutes, int? excludeId = null)
{
    await using var db = await factory.CreateDbContextAsync();
    var end = start.AddMinutes(durationMinutes);
    return await db.Appointments
        .Where(a => a.Status != AppointmentStatus.Cancelled
                 && (excludeId == null || a.Id != excludeId)
                 && a.StartTime < end
                 && EF.Functions.DateDiffMinute(a.StartTime, start) < a.DurationMinutes * -1 == false
                 && start < a.StartTime.AddMinutes(a.DurationMinutes)
                 )
        .ToListAsync();
}

public async Task<bool> HasConflict(DateTime start, int durationMinutes, int? excludeId = null)
{
    await using var db = await factory.CreateDbContextAsync();
    var end = start.AddMinutes(durationMinutes);
    return await db.Appointments
        .Where(a => a.Status != AppointmentStatus.Cancelled)
        .Where(a => excludeId == null || a.Id != excludeId)
        .AnyAsync(a => a.StartTime < end && start < a.StartTime.AddMinutes(a.DurationMinutes));
}

arguments.new_str:
public async Task<bool> HasConflict(DateTime start, int durationMinutes, int? excludeId = null)
{
    await using var db = await factory.CreateDbContextAsync();
    var end = start.AddMinutes(durationMinutes);
    // SQLite doesn't support AddMinutes in LINQ, so load active appointments for the day and check in memory
    var dayStart = start.Date;
    var dayEnd = dayStart.AddDays(1);
    var dayAppts = await db.Appointments
        .Where(a => a.Status != AppointmentStatus.Cancelled)
        .Where(a => excludeId == null || a.Id != excludeId)
        .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
        .ToListAsync();
    return dayAppts.Any(a => a.StartTime < end && start < a.StartTime.AddMinutes(a.DurationMinutes));
}

